const YOUTUBE_URL_PATTERN =
  /^(https?:\/\/)?(www\.|m\.)?(youtube\.com\/(watch\?v=|shorts\/|embed\/)|youtu\.be\/)[\w-]{11}([&?#].*)?$/;

export function isValidYouTubeUrl(url: string): boolean {
  return YOUTUBE_URL_PATTERN.test(url.trim());
}

export function validateForm(urls: string[], apiKey: string): string[] {
  const errors: string[] = [];
  const trimmed = urls.map((url) => url.trim());

  if (trimmed.every((url) => url === "")) {
    errors.push("Add at least one YouTube video URL.");
  }

  trimmed.forEach((url, index) => {
    if (url !== "" && !isValidYouTubeUrl(url)) {
      errors.push(`Video ${index + 1}: "${url}" is not a valid YouTube URL.`);
    }
  });

  if (apiKey.trim() === "") {
    errors.push("An OpenAI API key is required.");
  }

  return errors;
}

