import { MAX_VIDEO_URLS, MIN_VIDEO_URLS } from "@/lib/types";

interface VideoUrlFieldsProps {
  urls: string[];
  onChange: (urls: string[]) => void;
  disabled?: boolean;
}

export default function VideoUrlFields({
  urls,
  onChange,
  disabled = false,
}: VideoUrlFieldsProps) {
  const updateUrl = (index: number, value: string) => {
    onChange(urls.map((url, i) => (i === index ? value : url)));
  };

  const addField = () => {
    if (urls.length < MAX_VIDEO_URLS) onChange([...urls, ""]);
  };

  const removeField = (index: number) => {
    if (urls.length > MIN_VIDEO_URLS) {
      onChange(urls.filter((_, i) => i !== index));
    }
  };

  return (
    <div className="space-y-2">
      <label className="block text-sm font-medium text-gray-700">
        YouTube video URLs{" "}
        <span className="font-normal text-gray-400">
          ({urls.length}/{MAX_VIDEO_URLS})
        </span>
      </label>
      {urls.map((url, index) => (
        <div key={index} className="flex gap-2">
          <input
            type="url"
            value={url}
            onChange={(e) => updateUrl(index, e.target.value)}
            disabled={disabled}
            placeholder="https://www.youtube.com/watch?v=..."
            aria-label={`YouTube video URL ${index + 1}`}
            className="flex-1 rounded-lg border border-gray-300 px-3 py-2 text-sm placeholder-gray-400 focus:border-blue-500 focus:outline-none focus:ring-1 focus:ring-blue-500 disabled:bg-gray-100"
          />
          {urls.length > MIN_VIDEO_URLS && (
            <button
              type="button"
              onClick={() => removeField(index)}
              disabled={disabled}
              aria-label={`Remove video URL ${index + 1}`}
              className="rounded-lg border border-gray-300 px-3 py-2 text-sm text-gray-500 hover:bg-gray-100 hover:text-red-600 disabled:opacity-50"
            >
              Remove
            </button>
          )}
        </div>
      ))}
      {urls.length < MAX_VIDEO_URLS && (
        <button
          type="button"
          onClick={addField}
          disabled={disabled}
          className="text-sm font-medium text-blue-600 hover:text-blue-800 disabled:opacity-50"
        >
          + Add another video
        </button>
      )}
    </div>
  );
}

