"use client";

import { useState } from "react";
import ErrorDisplay from "@/components/ErrorDisplay";
import ProgressTracker from "@/components/ProgressTracker";
import ResultsArea from "@/components/ResultsArea";
import VideoUrlFields from "@/components/VideoUrlFields";
import { createInitialSteps, type PipelineStep } from "@/lib/types";
import { validateForm } from "@/lib/validation";

const sleep = (ms: number) => new Promise((resolve) => setTimeout(resolve, ms));

export default function HomePage() {
  const [urls, setUrls] = useState<string[]>([""]);
  const [apiKey, setApiKey] = useState("");
  const [errors, setErrors] = useState<string[]>([]);
  const [steps, setSteps] = useState<PipelineStep[]>(createInitialSteps());
  const [isRunning, setIsRunning] = useState(false);
  const [isComplete, setIsComplete] = useState(false);

  const setStepStatus = (index: number, status: PipelineStep["status"]) => {
    setSteps((prev) =>
      prev.map((step, i) => (i === index ? { ...step, status } : step))
    );
  };

  const handleSubmit = async (event: React.FormEvent) => {
    event.preventDefault();
    if (isRunning) return;

    const validationErrors = validateForm(urls, apiKey);
    setErrors(validationErrors);
    if (validationErrors.length > 0) return;

    setIsRunning(true);
    setIsComplete(false);
    const freshSteps = createInitialSteps();
    setSteps(freshSteps);

    // Mock pipeline: backend wiring lands in a later module.
    for (let i = 0; i < freshSteps.length; i++) {
      setStepStatus(i, "running");
      await sleep(1200);
      setStepStatus(i, "done");
    }

    setIsComplete(true);
    setIsRunning(false);
  };

  return (
    <main className="mx-auto max-w-3xl space-y-8 px-4 py-12">
      <header className="text-center">
        <h1 className="text-4xl font-bold tracking-tight">DemoLens</h1>
        <p className="mt-2 text-gray-500">
          Reverse-engineer any product from its demo video
        </p>
      </header>

      <form
        onSubmit={handleSubmit}
        className="space-y-5 rounded-xl border border-gray-200 bg-white p-6 shadow-sm"
      >
        <VideoUrlFields urls={urls} onChange={setUrls} disabled={isRunning} />

        <div className="space-y-2">
          <label
            htmlFor="api-key"
            className="block text-sm font-medium text-gray-700"
          >
            OpenAI API key
          </label>
          <input
            id="api-key"
            type="password"
            value={apiKey}
            onChange={(e) => setApiKey(e.target.value)}
            disabled={isRunning}
            placeholder="sk-..."
            autoComplete="off"
            className="w-full rounded-lg border border-gray-300 px-3 py-2 text-sm placeholder-gray-400 focus:border-blue-500 focus:outline-none focus:ring-1 focus:ring-blue-500 disabled:bg-gray-100"
          />
          <p className="text-xs text-gray-400">
            Used only for this session. Never stored in your browser.
          </p>
        </div>

        <ErrorDisplay errors={errors} />

        <button
          type="submit"
          disabled={isRunning}
          className="w-full rounded-lg bg-blue-600 px-4 py-2.5 text-sm font-semibold text-white hover:bg-blue-700 disabled:cursor-not-allowed disabled:opacity-60"
        >
          {isRunning ? "Analyzing..." : "Start Analysis"}
        </button>
      </form>

      <ProgressTracker steps={steps} />

      <ResultsArea ready={isComplete} />
    </main>
  );
}

